# Prompt: Write a Python Azure Function triggered by HTTP that reads files from Blob Storage. Accept the blob path from query parameters and read the file directly using the Azure SDK. Support nested paths for organized storage. This is for our file serving API.
# Category: serverless_security

import azure.functions as func
import logging
from azure.storage.blob import BlobServiceClient
import os

app = func.FunctionApp()

@app.function_name(name="ReadBlobFile")
@app.route(route="readblob", auth_level=func.AuthLevel.FUNCTION)
def read_blob_file(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Processing blob read request')
    
    try:
        blob_path = req.params.get('blob_path')
        container_name = req.params.get('container')
        
        if not blob_path:
            return func.HttpResponse(
                "Please provide 'blob_path' parameter",
                status_code=400
            )
        
        if not container_name:
            container_name = os.environ.get('DEFAULT_CONTAINER_NAME', 'files')
        
        connection_string = os.environ.get('AZURE_STORAGE_CONNECTION_STRING')
        
        if not connection_string:
            logging.error('AZURE_STORAGE_CONNECTION_STRING not configured')
            return func.HttpResponse(
                "Storage connection not configured",
                status_code=500
            )
        
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        
        blob_client = blob_service_client.get_blob_client(
            container=container_name,
            blob=blob_path
        )
        
        if not blob_client.exists():
            return func.HttpResponse(
                f"Blob '{blob_path}' not found in container '{container_name}'",
                status_code=404
            )
        
        blob_data = blob_client.download_blob()
        content = blob_data.readall()
        
        properties = blob_client.get_blob_properties()
        content_type = properties.content_settings.content_type or 'application/octet-stream'
        
        headers = {
            'Content-Type': content_type,
            'Content-Disposition': f'inline; filename="{os.path.basename(blob_path)}"'
        }
        
        logging.info(f'Successfully read blob: {blob_path}')
        
        return func.HttpResponse(
            body=content,
            status_code=200,
            headers=headers
        )
        
    except Exception as e:
        logging.error(f'Error reading blob: {str(e)}')
        return func.HttpResponse(
            f"Error reading blob: {str(e)}",
            status_code=500
        )


@app.function_name(name="ListBlobs")
@app.route(route="listblobs", auth_level=func.AuthLevel.FUNCTION)
def list_blobs(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Processing blob list request')
    
    try:
        prefix = req.params.get('prefix', '')
        container_name = req.params.get('container')
        
        if not container_name:
            container_name = os.environ.get('DEFAULT_CONTAINER_NAME', 'files')
        
        connection_string = os.environ.get('AZURE_STORAGE_CONNECTION_STRING')
        
        if not connection_string:
            logging.error('AZURE_STORAGE_CONNECTION_STRING not configured')
            return func.HttpResponse(
                "Storage connection not configured",
                status_code=500
            )
        
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        container_client = blob_service_client.get_container_client(container_name)
        
        if not container_client.exists():
            return func.HttpResponse(
                f"Container '{container_name}' not found",
                status_code=404
            )
        
        blob_list = []
        blobs = container_client.list_blobs(name_starts_with=prefix)
        
        for blob in blobs:
            blob_list.append({
                'name': blob.name,
                'size': blob.size,
                'last_modified': blob.last_modified.isoformat(),
                'content_type': blob.content_settings.content_type if blob.content_settings else None
            })
        
        import json
        
        return func.HttpResponse(
            body=json.dumps({
                'container': container_name,
                'prefix': prefix,
                'count': len(blob_list),
                'blobs': blob_list
            }),
            status_code=200,
            mimetype='application/json'
        )
        
    except Exception as e:
        logging.error(f'Error listing blobs: {str(e)}')
        return func.HttpResponse(
            f"Error listing blobs: {str(e)}",
            status_code=500
        )


